#include <gtest/gtest.h>

#include "solvers/coloring.h"

TEST(TestColoring, SimpleColoringT1) {
    //
    Inst inst = {
        0x70,//type
        5,//
        8,0x13,0x28,0x30,0x47,0x54,0x65,0x72,0x86,//color 1
        6,0x17,0x33,0x42,0x56,0x60,0x78,//color2
        0x23,0x05//executees
    };
    std::vector<uint16_t> executees = {0x2305};
    Grid grid("");
    findSimpleColoring(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}


TEST(TestColoring, SimpleColoringT2) {
    //(r1c8,r2c5,r5c4,r8c2) / (r2c9,r5c8,r8c5,r9c2) => r9c4<>7
    Inst inst = {
        0x70,//type
        6,//target
        4,0x07,0x14,0x43,0x71,//color 1
        4,0x18,0x47,0x74,0x81,//color2
        0x83,0x06//executees
    };
    std::vector<uint16_t> executees = {0x8306 };
    Grid grid("");
    findSimpleColoring(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

TEST(TestColoring, SDFT1) {
    //// target: 8, (3,9)(5,4)(2,2)(1,5)(6,8) r9
    Inst inst = {
        0xE0,//type
        7,//target
        4,//length
        0x13,0x48,0x20,0x06,//chain
        0x6f,//conflict
        0x13,0x07//executee
    };
    std::vector<uint16_t> executees = {0x1307};
    Grid grid("");
    findSingleDigitForcing(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}


